// OpenCL kernel for streamcluster pgain computation

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

// Kernel to compute distance costs and update switch membership
__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    int num,
    int dim,
    long x,
    int K
) {
    int i = get_global_id(0);

    if (i >= num) return;

    // Compute distance from point i to candidate center x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int center_idx = center_table[assign];
        if (center_idx >= 0 && center_idx < K) {
            work_mem[i * (K + 1) + center_idx] += current_cost - x_cost;
        }
    }
}
